onOptionChange:
{{
(() => {

  const newValue = Number(Select_YesNo.selectedOptionValue);
  const current = appsmith.store.answers?.[currentItem.id] || {};

  const updatedAnswers = {
    ...appsmith.store.answers,
    [currentItem.id]: {
      ...current,

      YesNo: newValue,

      // 🔥 FIXED USER SOURCE
      AnsweredBy: appsmith.store.userContext?.name || "Unknown",

      AnsweredDate: new Date().toISOString()
    }
  };

  // 🔹 If YES → remove extra fields
  if (newValue === 1) {
    delete updatedAnswers[currentItem.id].ResponsiblePerson;
    delete updatedAnswers[currentItem.id].Action;
    delete updatedAnswers[currentItem.id].DueDate;
  }

  // 🔹 If NO → ensure fields exist
  if (newValue === 0) {
    updatedAnswers[currentItem.id].ResponsiblePerson =
      current.ResponsiblePerson || "";

    updatedAnswers[currentItem.id].Action =
      current.Action || "";

    updatedAnswers[currentItem.id].DueDate =
      current.DueDate || "";
  }

  return storeValue("answers", updatedAnswers);

})()
}}
